 5→
 6→interface HomeProps {
 7→  onNavigate: (view: string) => void;
 8→  user: User | null;
 9→}
10→
11→// Deterministic score simulation based on URL
12→const simulateEEATScore = (brandName: string, url: string) => {
13→  let hash = 0;
14→  const seed = brandName + url;
15→  for (let i = 0; i < seed.length; i++) {
16→    hash = ((hash << 5) - hash) + seed.charCodeAt(i);
17→    hash = hash & hash;
18→  }
19→  const base = Math.abs(hash % 40) + 35; // Score between 35-75
20→  return {
21→    global: base,
22→    experience: Math.min(100, base + (Math.abs(hash >> 4) % 20) - 10),
23→    expertise: Math.min(100, base + (Math.abs(hash >> 8) % 20) - 10),
24→    authority: Math.min(100, base + (Math.abs(hash >> 12) % 20) - 10),
25→    trust: Math.min(100, base + (Math.abs(hash >> 16) % 20) - 10),
26→  };
27→};
28→
29→const Home: React.FC<HomeProps> = ({ onNavigate, user }) => {
