31→  const [freeScoreUrl, setFreeScoreUrl] = useState('');
32→  const [isCalculating, setIsCalculating] = useState(false);
33→  const [freeScoreResult, setFreeScoreResult] = useState<ReturnType<typeof simulateEEATScore> | null>(null);
34→
35→  const handleStartAnalysis = () => {
36→    if (user) {
37→      onNavigate('analyze');
38→    } else {
39→      onNavigate('login');
40→    }
41→  };
42→
43→  const handleFreeScore = async () => {
44→    if (!freeScoreBrand || !freeScoreUrl) return;
45→    setIsCalculating(true);
46→    // Simulate processing
47→    await new Promise(resolve => setTimeout(resolve, 2000));
48→    const result = simulateEEATScore(freeScoreBrand, freeScoreUrl);
49→    setFreeScoreResult(result);
50→    setIsCalculating(false);

