import React, { useState, useRef, useCallback } from 'react';
import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck, ShieldCheck, Lock, Headphones, Flag, ChevronDown } from 'lucide-react';
import { User } from '../types';
import ScoreRing from '../components/ScoreRing';
import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';

interface HomeProps {
  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  user: User | null;
  onDirectRecharge?: (packId: number) => void;
}

const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {

  // ── FAQ State ──
  const [openFaq, setOpenFaq] = useState<number | null>(null);

  // ── Score Gratuit State ──
  const [brandName, setBrandName] = useState('');
  const [siteUrl, setSiteUrl] = useState('');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
  const [auditError, setAuditError] = useState<string | null>(null);
  const resultsRef = useRef<HTMLDivElement>(null);

  // Derive E-E-A-T pillar scores from the 6 audit categories
  const eeatPillars = auditResult ? [
    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
  ] : [];

  const handleFreeAudit = useCallback(async () => {
    if (!brandName.trim() || !siteUrl.trim()) {
      setAuditError('Veuillez remplir les deux champs.');
      return;
    }
    // Basic URL validation
    let finalUrl = siteUrl.trim();
    if (!/^https?:\/\//i.test(finalUrl)) {
      finalUrl = 'https://' + finalUrl;
    }
    try {
      new URL(finalUrl);
    } catch {
      setAuditError('URL invalide. Exemple : https://www.example.com');
      return;
    }

    setAuditError(null);
    setAuditResult(null);
    setIsAnalyzing(true);

    try {
      const result = await auditAnswerFirst(finalUrl, brandName.trim());
      setAuditResult(result);
      // Scroll to results after a small delay for render
      setTimeout(() => {
        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }, 150);
    } catch (err) {
      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
    } finally {
      setIsAnalyzing(false);
    }
  }, [brandName, siteUrl]);

  const getScoreLabel = (score: number): string => {
    if (score >= 80) return 'Excellent';
    if (score >= 60) return 'Bon';
    if (score >= 40) return 'Moyen';
    if (score >= 20) return 'Faible';
    return 'Critique';
  };

  const getScoreColor = (score: number): string => {
    if (score >= 80) return 'text-purple-400';
    if (score >= 60) return 'text-violet-400';
    if (score >= 40) return 'text-amber-400';
    return 'text-red-400';
  };

  const getBarColor = (score: number): string => {
    if (score >= 80) return 'bg-purple-500';
    if (score >= 60) return 'bg-violet-500';
    if (score >= 40) return 'bg-amber-500';
    return 'bg-red-500';
  };

  const handleStartAnalysis = () => {
    if (user) {
      onNavigate('analyze');
    } else {
      onNavigate('login');
    }
  };

  const handleSelectPlan = (packId: number) => {
    if (user) {
      if (onDirectRecharge) {
        onDirectRecharge(packId);
      } else {
        onNavigate('recharge');
      }
    } else {
      onNavigate('login');
    }
  };

  const plans = [
    {
      id: 1,
      name: "Le Jerrican",
      credits: 50,
      price: 15,
      icon: <Droplet size={24} />,
      popular: false,
      features: ["Id\u00e9al pour tester", "1 Audit complet", "Valable 1 an"]
    },
    {
      id: 2,
      name: "La Pompe",
      credits: 200,
      price: 49,
      icon: <Fuel size={24} />,
      popular: true,
      features: ["Pour optimiser s\u00e9rieusement", "Support prioritaire", "+10% Bonus offert"]
    },
    {
      id: 3,
      name: "La Citerne",
      credits: 1000,
      price: 199,
      icon: <Database size={24} />,
      popular: false,
      features: ["Usage intensif / Agence", "Acc\u00e8s API Beta", "+20% Bonus offert"]
    }
  ];

  return (
    <div className="w-full px-6 pt-16 pb-32 overflow-hidden">

      {/* ── HERO SECTION ── */}
      <div className="text-center mb-32 relative">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[700px] h-[500px] bg-purple-600/8 blur-[150px] rounded-full -z-10 pointer-events-none"></div>

        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
          <Sparkles size={12} className="text-purple-400" />
          <span>Plateforme AEO / GEO</span>
        </div>

        <h1 className="text-5xl sm:text-6xl md:text-[5.5rem] font-sans font-bold tracking-tight text-white leading-[1.05] mb-8">
          Faites-vous citer{' '}
          <br className="hidden md:block" />
          par les <span className="gradient-text">IA G{'\u00e9'}n{'\u00e9'}ratives</span>
        </h1>

        <p className="text-lg md:text-xl text-gray-500 max-w-2xl mx-auto leading-relaxed mb-12 font-light">
          La premi{'\u00e8'}re plateforme d'optimisation AEO. Analysez et influencez la fa{'\u00e7'}on dont ChatGPT, Claude, Gemini et AI Overviews per{'\u00e7'}oivent votre marque.
        </p>

        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
          <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30">
            Lancer un Audit Gratuit <ArrowRight size={18} />
          </button>
          <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.1] text-gray-300 text-base font-medium hover:bg-white/[0.04] hover:border-white/[0.15] transition-all">
            Explorer l'Annuaire
          </button>
        </div>
      </div>

      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
      <div className="mb-32 relative" id="score-gratuit">
        {/* Ambient glow */}
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[600px] bg-purple-600/[0.06] blur-[180px] rounded-full -z-10 pointer-events-none"></div>

        {/* Section header */}
        <div className="text-center mb-12">
          {/* GRATUIT Banner */}
          <div className="inline-flex items-center gap-2 px-5 py-2 rounded-full bg-gradient-to-r from-purple-500/20 to-violet-600/20 border border-purple-500/30 text-white text-sm font-bold tracking-wide uppercase mb-8 shadow-lg shadow-purple-600/10">
            <Gift size={16} className="text-purple-400" />
            <span>100% GRATUIT</span>
            <span className="text-purple-400">&mdash;</span>
            <span className="text-purple-300">Sans inscription</span>
          </div>

          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Votre Score de <span className="gradient-text">Visibilit{'\u00e9'} IA</span>
          </h2>
          <p className="text-gray-500 max-w-2xl mx-auto text-lg">
            D{'\u00e9'}couvrez en 30 secondes comment les IA g{'\u00e9'}n{'\u00e9'}ratives per{'\u00e7'}oivent votre marque. Aucun compte requis.
          </p>
        </div>

        {/* Form + Results Container */}
        <div className="max-w-3xl mx-auto">
          {/* Form Card */}
          <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
            {/* Decorative gradient line at top */}
            <div className="absolute top-0 left-0 right-0 h-[2px] bg-gradient-to-r from-transparent via-purple-500 to-transparent"></div>

            <form
              onSubmit={(e) => { e.preventDefault(); handleFreeAudit(); }}
              className="space-y-5"
            >
              <div className="grid md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">Nom de marque</label>
                  <input
                    type="text"
                    value={brandName}
                    onChange={(e) => setBrandName(e.target.value)}
                    placeholder="Ex: CitedBy"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-300 mb-2">URL du site</label>
                  <input
                    type="text"
                    value={siteUrl}
                    onChange={(e) => setSiteUrl(e.target.value)}
                    placeholder="Ex: https://www.citedby.ai"
                    className="w-full px-4 py-3 rounded-xl bg-white/[0.04] border border-white/[0.08] text-white placeholder-gray-600 outline-none transition-all focus:border-purple-500/50 focus:bg-white/[0.06] focus:shadow-[0_0_20px_rgba(168,85,247,0.08)]"
                    disabled={isAnalyzing}
                  />
                </div>
              </div>

              {auditError && (
                <p className="text-sm text-red-400 bg-red-500/10 border border-red-500/20 rounded-xl px-4 py-2.5">{auditError}</p>
              )}

              <button
                type="submit"
                disabled={isAnalyzing}
                className="w-full btn-gradient py-4 text-base font-bold flex items-center justify-center gap-3 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 disabled:opacity-60 disabled:cursor-not-allowed transition-all"
              >
                {isAnalyzing ? (
                  <>
                    <Loader2 size={20} className="animate-spin" />
                    Analyse en cours...
                  </>
                ) : (
                  <>
                    <Sparkles size={20} />
                    Analyser gratuitement
                  </>
                )}
              </button>

              <p className="text-center text-xs text-gray-600">
                Aucune carte bancaire requise. 0 GTO Gas consomm{'\u00e9'}. R{'\u00e9'}sultat instantan{'\u00e9'}.
              </p>
            </form>
          </div>

          {/* Loading Animation */}
          {isAnalyzing && (
            <div className="mt-8 ninja-card p-10 flex flex-col items-center justify-center gap-5">
              <div className="relative">
                <div className="w-24 h-24 rounded-full border-4 border-white/[0.06]"></div>
                <div className="absolute inset-0 w-24 h-24 rounded-full border-4 border-transparent border-t-purple-500 animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                  <ScanLine size={28} className="text-purple-400 animate-pulse" />
                </div>
              </div>
              <div className="text-center">
                <p className="text-white font-semibold mb-1">Scan en cours...</p>
                <p className="text-sm text-gray-500">Nous interrogeons les LLMs pour {'\u00e9'}valuer votre marque</p>
              </div>
              {/* Animated category tags */}
              <div className="flex flex-wrap justify-center gap-2">
                {['Answer-First', 'Schema.org', 'FAQ', 'S\u00e9mantique', 'Fra\u00eecheur', 'Meta'].map((label, i) => (
                  <div
                    key={label}
                    className="px-3 py-1 rounded-full text-[10px] font-medium bg-white/[0.04] border border-white/[0.06] text-gray-500"
                    style={{ animation: `pulse 1.5s ease-in-out ${i * 0.25}s infinite` }}
                  >
                    {label}
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Results Section */}
          {auditResult && !isAnalyzing && (
            <div ref={resultsRef} className="mt-8 space-y-6">
              {/* Main Score Card */}
              <div className="ninja-card p-8 md:p-10 relative overflow-hidden">
                {/* GRATUIT tag */}
                <div className="absolute top-0 right-0 px-5 py-1.5 bg-gradient-to-r from-purple-500 to-violet-600 text-xs font-bold rounded-bl-2xl rounded-tr-[1rem] text-white uppercase tracking-wider">
                  GRATUIT
                </div>

                <div className="flex flex-col md:flex-row items-center gap-8 md:gap-12">
                  {/* ScoreRing */}
                  <div className="flex flex-col items-center gap-3 shrink-0">
                    <ScoreRing score={auditResult.globalScore} size={160} strokeWidth={10} />
                    <div className={`text-sm font-bold ${getScoreColor(auditResult.globalScore)}`}>
                      {getScoreLabel(auditResult.globalScore)}
                    </div>
                  </div>

                  {/* E-E-A-T Pillars */}
                  <div className="flex-1 w-full">
                    <h3 className="text-lg font-bold text-white mb-5 flex items-center gap-2">
                      <Shield size={18} className="text-purple-400" />
                      Piliers E-E-A-T
                    </h3>
                    <div className="space-y-4">
                      {eeatPillars.map((pillar) => (
                        <div key={pillar.label}>
                          <div className="flex items-center justify-between mb-1.5">
                            <div className="flex items-center gap-2">
                              <span className="text-purple-400">{pillar.icon}</span>
                              <span className="text-sm font-medium text-gray-300">{pillar.label}</span>
                            </div>
                            <span className={`text-sm font-bold ${getScoreColor(pillar.score)}`}>{pillar.score}/100</span>
                          </div>
                          <div className="w-full h-2.5 bg-white/[0.06] rounded-full overflow-hidden">
                            <div
                              className={`h-full rounded-full transition-all duration-1000 ease-out ${getBarColor(pillar.score)}`}
                              style={{ width: `${pillar.score}%` }}
                            ></div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                </div>
              </div>

              {/* Summary Card */}
              <div className="ninja-card p-8">
                <h3 className="text-lg font-bold text-white mb-4 flex items-center gap-2">
                  <Target size={18} className="text-purple-400" />
                  Synth{'\u00e8'}se
                </h3>
                <p className="text-gray-400 leading-relaxed text-[15px] mb-6">{auditResult.summary}</p>

                {auditResult.topRecommendations.length > 0 && (
                  <div>
                    <h4 className="text-sm font-bold text-gray-300 mb-3 uppercase tracking-wider">Recommandations prioritaires</h4>
                    <ul className="space-y-2.5">
                      {auditResult.topRecommendations.map((rec, i) => (
                        <li key={i} className="flex items-start gap-3 text-sm text-gray-400">
                          <div className="w-5 h-5 rounded-full bg-purple-500/20 flex items-center justify-center shrink-0 mt-0.5">
                            <span className="text-[10px] font-bold text-purple-400">{i + 1}</span>
                          </div>
                          {rec}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </div>

              {/* CTA Card */}
              <div className="gradient-border p-8 text-center relative overflow-hidden">
                {/* Grid pattern */}
                <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
                <div className="relative z-10">
                  <h3 className="text-xl md:text-2xl font-bold text-white mb-3">
                    D{'\u00e9'}bloquez l'analyse <span className="gradient-text">compl{'\u00e8'}te</span>
                  </h3>
                  <p className="text-gray-500 mb-6 max-w-lg mx-auto">
                    Cr{'\u00e9'}ez votre compte pour acc{'\u00e9'}der {'\u00e0'} l'audit d{'\u00e9'}taill{'\u00e9'} avec recommandations personnalis{'\u00e9'}es, outils de correction et monitoring continu.
                  </p>
                  <button
                    onClick={() => onNavigate('login')}
                    className="btn-gradient text-base px-8 py-3.5 inline-flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30"
                  >
                    Cr{'\u00e9'}ez votre compte pour l'analyse compl{'\u00e8'}te <ArrowRight size={18} />
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ── STATS BAR ── */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-32">
        {[
          { value: '50%', label: 'des recherches vont vers l\'IA', sublabel: 'd\'ici 2026' },
          { value: '24h', label: 'pour \u00eatre cit\u00e9', sublabel: 'premier audit' },
          { value: '0', label: 'clic n\u00e9cessaire', sublabel: 'r\u00e9ponse directe' },
          { value: '3x', label: 'plus de conversions', sublabel: 'vs SEO classique' },
        ].map((stat, i) => (
          <div key={i} className="ninja-card p-6 text-center group cursor-pointer hover:-translate-y-1 transition-all duration-300" style={{ animationDelay: `${i * 150}ms`, animation: `slide-in-from-bottom 0.5s ease-out ${i * 150}ms both` }}>
            <div className="text-3xl md:text-4xl font-bold gradient-text mb-2 group-hover:scale-110 transition-transform duration-300">{stat.value}</div>
            <p className="text-sm text-gray-300 font-medium">{stat.label}</p>
            <p className="text-xs text-gray-600 mt-1">{stat.sublabel}</p>
          </div>
