          <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Notre monnaie virtuelle pour ex{'\u00e9'}cuter les audits, g{'\u00e9'}n{'\u00e9'}rer les correctifs et valider votre entit{'\u00e9'}.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-5 w-full items-stretch">
          {plans.map((plan, idx) => (
            <div
              key={idx}
              className={`relative ninja-card p-8 flex flex-col h-full cursor-pointer ${
                plan.popular
                  ? '!border-purple-500/30 shadow-[0_0_50px_rgba(168,85,247,0.08)] md:scale-105 z-10'
                  : ''
