          <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-6">
            <Fuel size={12} className="text-purple-400" />
            <span>Carburant Algorithmique</span>
          </div>
          <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
            Rechargez votre <span className="gradient-text">GTO Gas</span>
          </h2>
          <p className="text-gray-500 max-w-xl mx-auto text-lg">
            Notre monnaie virtuelle pour ex{'\u00e9'}cuter les audits, g{'\u00e9'}n{'\u00e9'}rer les correctifs et valider votre entit{'\u00e9'}.
          </p>
        </div>

        <div className="grid md:grid-cols-3 gap-5 w-full items-stretch">
          {plans.map((plan, idx) => (
            <div
              key={idx}
              className={`relative ninja-card p-8 flex flex-col h-full cursor-pointer ${
                plan.popular
                  ? '!border-purple-500/30 shadow-[0_0_50px_rgba(168,85,247,0.08)] md:scale-105 z-10'
                  : ''
              }`}
            >
              {plan.popular && (
                <div className="absolute -top-4 left-1/2 -translate-x-1/2 btn-gradient text-xs font-bold px-5 py-1.5 rounded-full uppercase tracking-wider shadow-lg shadow-purple-600/30">
                  Le Choix Expert
                </div>
              )}

              <div className="mb-6 flex items-center justify-between pt-2">
                <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${
                  plan.popular
                    ? 'bg-gradient-to-br from-purple-500 to-violet-600 text-white'
                    : 'bg-purple-500/10 text-gray-500'
                }`}>
                  {plan.icon}
                </div>
                <div className="text-right">
                  <span className="block text-3xl font-bold gradient-text">{plan.credits}</span>
                  <span className="text-[11px] text-gray-600 uppercase font-bold tracking-wider">Cr{'\u00e9'}dits Gas</span>
                </div>
              </div>

              <h3 className="text-xl font-bold text-white mb-2">{plan.name}</h3>
              <div className="flex items-baseline gap-1 mb-8">
                <span className="text-4xl font-bold text-white">{plan.price}{'\u20ac'}</span>
                <span className="text-sm text-gray-600">HT</span>
              </div>

              <ul className="space-y-3.5 mb-8 flex-1">
                {plan.features.map((feat, i) => (
                  <li key={i} className="flex items-start gap-3 text-[15px] text-gray-400">
                    <Check size={16} className={`mt-0.5 shrink-0 ${plan.popular ? 'text-purple-400' : 'text-gray-600'}`} />
                    {feat}
                  </li>
                ))}
              </ul>

              <button
                onClick={() => handleSelectPlan(plan.id)}
                className={`w-full py-3.5 rounded-full font-bold flex items-center justify-center gap-2 transition-all text-[15px] ${
                  plan.popular
                    ? 'btn-gradient shadow-lg shadow-purple-600/20'
                    : 'bg-white/[0.04] border border-white/[0.08] text-gray-300 hover:bg-white/[0.07] hover:border-white/[0.12]'
                }`}
              >
                {user ? 'Recharger' : 'Cr\u00e9er un compte'} <ArrowRight size={16} />
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* ── FINAL CTA SECTION ── */}
      <div className="mt-20 mb-8">
        <div className="gradient-border p-10 md:p-16 text-center relative overflow-hidden">
          {/* Grid pattern */}
          <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'linear-gradient(rgba(255, 255, 255, 0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255, 255, 255, 0.02) 1px, transparent 1px)', backgroundSize: '24px 24px' }}></div>
          {/* Ambient glow */}
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[500px] h-[300px] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none"></div>

          <div className="relative z-10">
            <h2 className="text-3xl md:text-5xl font-sans font-bold text-white tracking-tight mb-5">
              Pr{'\u00ea'}t {'\u00e0'} dominer les <span className="gradient-text">r{'\u00e9'}ponses IA</span> ?
            </h2>
            <p className="text-gray-500 max-w-xl mx-auto text-lg mb-10">
              Rejoignez les marques qui se font citer par ChatGPT, Claude et Gemini.
            </p>
            <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
              <button onClick={handleStartAnalysis} className="btn-gradient text-base px-8 py-3.5 flex items-center gap-2.5 shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30 transition-all duration-300">
                Commencer gratuitement <ArrowRight size={18} />
              </button>
              <button onClick={() => onNavigate('directory')} className="px-8 py-3.5 rounded-full border border-white/[0.1] text-gray-300 text-base font-medium hover:bg-white/[0.04] hover:border-white/[0.15] transition-all duration-300">
                Explorer l'Annuaire
              </button>
            </div>
          </div>
        </div>
      </div>

    </div>
  );
};

export default Home;
